use Storable qw(nstore retrieve);

# Create a new session
sub create_session {
    my ($session_id) = @_;

    # Serialize the session data to a file
    nstore($session_id, "/tmp/sess_$session_id");
}

# Load an existing session
sub load_session {
    my ($session_id) = @_;

    # Deserialize the session data from a file
    my $session_data = retrieve("/tmp/sess_$session_id");

